    core_functions: textCell(fields['核心功能']), materials_ingredients_technology: textCell(fields['材质成分技术']), specs_parameters: textCell(fields['规格参数']), usage_method: textCell(fields['使用方法']), usage_scenarios: textCell(fields['适用场景']),
    core_selling_points: textCell(fields['核心卖点']), unique_mechanism: textCell(fields['独特机制']), differentiation: textCell(fields['差异化优势']), core_transformation: textCell(fields['核心蜕变']), proof_points: textCell(fields['证据背书']),
    target_audience: textCell(fields['目标人群']), user_persona: textCell(fields['使用者画像']), buyer_persona: textCell(fields['购买者画像']), visceral_pain_points: textCell(fields['刺骨痛点']), emotional_triggers: textCell(fields['情绪触发器']), buyer_objections: textCell(fields['购买阻力']),
    visual_hook_elements: textCell(fields['视觉抓手']), offer_promo_guarantee: textCell(fields['优惠促销保障']), recommended_hook_categories: textCell(fields['推荐Hook分类']), risk_constraints: textCell(fields['禁说内容风险点']), manual_notes: textCell(fields['用户手动备注'])
  };
}

const base = $('Prepare hooks from product').first().json;
const token = await feishuToken();
const product = await getRecord(token, PRODUCT_TABLE, base.productRecordId);
const productUrl = urlCell(product.fields['产品链接']);
try {
  const parsed = parseJson($input.first().json);
  const hooks = Array.isArray(parsed.hooks) ? parsed.hooks : [];
  if (!hooks.length) throw new Error('Hook 生成结果为空。');
  const batch = base.mode + '-' + Date.now();
  const strategyMap = { default: '默认精选', append_same: '同类追加', append_new: '换分类', specified: '指定分类' };
  const productName = base.brief?.product_name || textCell(product.fields['产品名称']) || '';
  const records = hooks.map((h) => ({ fields: {
    '产品链接': urlValue(productUrl), '产品名称': productName, 'Hook分类': h.hook_category || '', 'Hook概念': h.hook_concept || '', '开头脚本_zh': h.hook_script_zh || '', '开头脚本_en': h.hook_script_en || '',
    'Rehook_zh': h.rehook_zh || '', 'Rehook_en': h.rehook_en || '', '认知阶段': h.awareness_level || 'problem', '情绪触发': h.emotion_trigger || '', '视觉开场': h.visual_hook || '', '收益桥接': h.benefit_bridge || '', '分类理由': h.category_rationale || '',
    '自评分': Number(h.self_score) || 0, '生成批次': batch, '分类策略': strategyMap[base.mode] || '默认精选', '脚本状态': '未生成', '关联产品': [base.productRecordId]
  }}));
  await batchCreate(token, HOOK_TABLE, records);
  await updateRecord(token, PRODUCT_TABLE, base.productRecordId, { '状态': '已生成', '已生成分类记录': (parsed.selected_categories || []).join(' / '), '错误信息': '' });
  return [{ json: { message: 'Hook generated', created: records.length, categories: parsed.selected_categories || [] } }];
} catch (error) {
  await updateRecord(token, PRODUCT_TABLE, base.productRecordId, { '状态': '失败', '错误信息': (error.message || String(error)).slice(0, 4000) });
  throw error;
}
